-- Create "copilot_conversations" table
CREATE TABLE "copilot_conversations" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "admin_user_id" bigint NOT NULL,
  "title" character varying NOT NULL DEFAULT '',
  "messages_json" text NOT NULL DEFAULT '[]',
  PRIMARY KEY ("id")
);
-- Create index "copilotconversation_admin_user_id_updated_at" to table: "copilot_conversations"
CREATE INDEX "copilotconversation_admin_user_id_updated_at" ON "copilot_conversations" ("admin_user_id", "updated_at");
